import{_ as a,o as n,c as t,ae as o}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"SAN API-Driven Deferred Deep Linking","description":"","frontmatter":{"title":"SAN API-Driven Deferred Deep Linking","slug":"san-deferred-deep-linking"},"headers":[],"relativePath":"developer-hub/san-deferred-deep-linking.md","filePath":"developer-hub/san-deferred-deep-linking.md"}'),s={name:"developer-hub/san-deferred-deep-linking.md"};function i(r,e,l,d,p,u){return n(),t("div",null,[...e[0]||(e[0]=[o(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>When a Branch SDK initializes within an app, it calls out to Branch and gets back deep link data. This historically has excluded data from Self-Attributing Networks (SANs), making it difficult to implement deferred deep linking (DDL).</p><p>With SAN API-Driven DDL, Branch actually returns SAN ad data as deep link data on new installs or reinstalls (<strong>not</strong> opens).</p><h3 id="san-support" tabindex="-1">SAN support <a class="header-anchor" href="#san-support" aria-label="Permalink to &quot;SAN support&quot;">​</a></h3><p>The following SANs are supported:</p><ul><li>Google</li><li>Meta</li></ul><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>On iOS, SAN Deferred Deep Linking will <strong>only</strong> work after the user opts-in to sharing their device data through <a href="https://developer.apple.com/app-store/user-privacy-and-data-use/" target="_blank" rel="noreferrer">Apple&#39;s AppTrackingTransparency framework</a>. This also means that there will be a delay due to the nature of the 2nd install event only occurring after a paid-attributed opt-in. For additional information on changes post iOS 14.5, visit our <a href="./ios-14-faqs.html">FAQ Pages</a>.</p></div><h2 id="enable-san-api-driven-ddl" tabindex="-1">Enable SAN API-Driven DDL <a class="header-anchor" href="#enable-san-api-driven-ddl" aria-label="Permalink to &quot;Enable SAN API-Driven DDL&quot;">​</a></h2><p>To use SAN API-Driven DDL, update the account settings for the ad partner you want it enabled for:</p><ol><li>Go to Branch, and navigate to <strong>Configure &gt; Ad Partners</strong>.</li><li>Search for and select the ad partner you want to enable SAN DDL for.</li><li>On the <strong>Account Settings</strong> tab for that ad partner, turn the <strong>Enable SAN API-Driven Deferred Deep Linking</strong> toggle on.</li></ol><p><strong>Important notes</strong>:</p><ul><li>If you were already using SAN DDL prior to the toggle feature, that SAN has been automatically enabled. No manual action is required.</li><li>If the toggle is not enabled, SAN API DDL will not return data, but other DDL methods (such as Instant Experience for Meta) are still supported independently.</li></ul><h2 id="view-san-deep-link-data" tabindex="-1">View SAN deep link data <a class="header-anchor" href="#view-san-deep-link-data" aria-label="Permalink to &quot;View SAN deep link data&quot;">​</a></h2><p>The fields available for routing will differ depending on the SAN. Below is a breakdown of what to expect from each supported network.</p><h4 id="data-availability" tabindex="-1">Data availability <a class="header-anchor" href="#data-availability" aria-label="Permalink to &quot;Data availability&quot;">​</a></h4><p><strong>Important</strong>: We will only return the information we get back from the SAN, which does not include any Branch Link control parameters (such as <code>$ios_url</code> or <code>$android_deeplink_path</code>) or attribution fields (such as <code>~campaign</code> or <code>~channel</code>), because there is no Branch Link involved. Even if you include a Branch Ad Link in the ad, that link&#39;s data will not be returned as part of this feature.</p><h3 id="google" tabindex="-1">Google <a class="header-anchor" href="#google" aria-label="Permalink to &quot;Google&quot;">​</a></h3><p>For Google SAN DDL, the fields your app should use for routing are:</p><ul><li><code>+from_google_ad</code> — Set to <code>true</code> when the install is attributed to a Google Ad. Use this as the primary signal to identify a Google SAN DDL response.</li><li><code>+non_branch_link</code> — Contains the deep link value passed from Google. This is the value your app should use to determine where to route the user.</li><li><code>+clicked_branch_link</code> — Will be <code>false</code> in these cases, since no Branch Link is involved.</li><li><code>+is_first_session</code> — Will be <code>true</code> for new installs.</li></ul><h4 id="response" tabindex="-1">Response <a class="header-anchor" href="#response" aria-label="Permalink to &quot;Response&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>    &quot;+from_google_ad&quot;: true,</span></span>
<span class="line"><span>    &quot;+non_branch_link&quot;: &quot;https://www.example.com/&quot;,</span></span>
<span class="line"><span>    &quot;+clicked_branch_link&quot;: false,</span></span>
<span class="line"><span>    &quot;+is_first_session&quot;: true</span></span>
<span class="line"><span>}</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Previously, Google SAN DDL returned a full metadata dictionary with fields like <code>~campaign</code>, <code>~ad_set_name</code>, and <code>~ad_id</code>. The new simplified format shown above replaces that response. The legacy format has been deprecated because it caused double-counting of installs reported to Google.</p><p>If your app currently parses the old format, you will need to update your routing logic to use <code>+non_branch_link</code> and <code>+from_google_ad</code> instead. Please contact our <a href="./submit-a-ticket.html">support team</a> to coordinate a transition timeline.</p></div><h3 id="meta" tabindex="-1">Meta <a class="header-anchor" href="#meta" aria-label="Permalink to &quot;Meta&quot;">​</a></h3><p>There are two ways to implement deferred deep linking with Meta ads:</p><ul><li><p><strong>SAN API DDL:</strong> Does not use a Branch Link and returns campaign-level data from Meta (e.g. campaign name, ad set ID). This approach works for <strong>App Install campaigns</strong>.</p><ul><li>For more information, see the SAN API DDL response payload below.</li></ul></li><li><p><strong>Instant Experience DDL</strong>: Uses a Branch Ad Link and returns full Branch Link data (e.g. <code>$deeplink_path</code>, <code>$canonical_url</code>). This approach works best for web-based campaigns driving app installs. It may also work for App Install campaigns, but introduces an additional interstitial step for users before the App Store page.</p><ul><li>For more information, visit the <a href="./facebook-ads-deferred-deep-linking.html">Meta Ads Deferred Deep Linking guide</a>.</li></ul></li></ul><h4 id="response-1" tabindex="-1">Response <a class="header-anchor" href="#response-1" aria-label="Permalink to &quot;Response&quot;">​</a></h4><p>The SAN API DDL response includes campaign-level data returned from Meta. Your app can use these fields to determine routing. Notice that the deep link data is inside <code>data</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>    &quot;session_id&quot;: &quot;1111111111111111111&quot;,</span></span>
<span class="line"><span>    &quot;identity_id&quot;: &quot;000000000000000000&quot;,</span></span>
<span class="line"><span>    &quot;link&quot;: &quot;https://abc.app.link?%24identity_id=123456789123456789&quot;,</span></span>
<span class="line"><span>    &quot;data&quot;: {</span></span>
<span class="line"><span>        &quot;+is_first_session&quot;: true,</span></span>
<span class="line"><span>        &quot;$3p&quot;: &quot;a_facebook&quot;,</span></span>
<span class="line"><span>        &quot;~advertising_partner_name&quot;: &quot;Facebook&quot;,</span></span>
<span class="line"><span>        &quot;+click_timestamp&quot;: 1557204842,</span></span>
<span class="line"><span>        &quot;~secondary_publisher&quot;: &quot;facebook&quot;,</span></span>
<span class="line"><span>        &quot;~campaign&quot;: &quot;Summer_Promo_2025&quot;,</span></span>
<span class="line"><span>        &quot;~campaign_id&quot;: &quot;22222333334444455555&quot;,</span></span>
<span class="line"><span>        &quot;~ad_set_name&quot;: &quot;US_Lookalike&quot;,</span></span>
<span class="line"><span>        &quot;~ad_set_id&quot;: &quot;6666777788889999&quot;,</span></span>
<span class="line"><span>        &quot;~ad_name&quot;: &quot;Video_Creative_A&quot;,</span></span>
<span class="line"><span>        &quot;~ad_id&quot;: &quot;0000111122223333&quot;,</span></span>
<span class="line"><span>        &quot;~feature&quot;: &quot;paid advertising&quot;,</span></span>
<span class="line"><span>        &quot;~ad_objective_name&quot;: &quot;APP_INSTALLS&quot;,</span></span>
<span class="line"><span>        &quot;~channel&quot;: &quot;Facebook&quot;</span></span>
<span class="line"><span>    },</span></span>
<span class="line"><span>    &quot;device_fingerprint_id&quot;: &quot;333444555666777&quot;</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><details><summary>Will my app get back Branch deep link data?</summary><p>No. SAN API DDL returns data from the SAN, not from a Branch Link. You will not receive Branch Link control parameters such as <code>$ios_url</code>, <code>$android_deeplink_path</code>, or <code>$canonical_url</code>.</p><p>Even if you include a Branch Ad Link in the ad, that link&#39;s data will not be returned as part of this feature.</p></details><details><summary>Do I need to update my app for SAN API DDL?</summary><p>Not necessarily. You need to have the <a href="./san-deferred-deep-linking.html#enable-san-apidriven-ddl">toggle enabled</a>, but no SDK update is required.</p><p>However, if you want to change your routing logic based on the new data coming back from SANs (e.g. show a specific in-app page for a specific campaign name), you will need to update your app code.</p></details><details><summary>Will I get ad data from impressions or view-throughs?</summary><p>No. SAN API DDL only returns click data (not view-through).</p></details><details><summary>If there are multiple recent clicks from different sources, which deep link data will I receive?</summary><p>You will receive the data from the most recent click, regardless of source.</p></details><details><summary>Does SAN API DDL work for reinstalls or opens?</summary><p>SAN API DDL works for new installs and reinstalls, but <strong>not</strong> for opens. Supporting opens would result in over-counting reinstalls and opens within partner reporting.</p></details><details><summary>What happens if the toggle is not enabled?</summary><p>If the <strong>Enable SAN API-Driven Deferred Deep Linking</strong> toggle is not enabled, SAN API DDL will not return data. Other DDL methods (such as Instant Experience for Meta) are still supported independently and are not affected by this toggle.</p></details><h3 id="google-1" tabindex="-1">Google <a class="header-anchor" href="#google-1" aria-label="Permalink to &quot;Google&quot;">​</a></h3><details><summary>I&#39;m using the old Google SAN DDL format with full metadata. Will this break?</summary><p>The legacy format (which returned a full metadata dictionary with fields like <code>~campaign</code>, <code>~ad_set_name</code>, and <code>~ad_id</code>) has been deprecated and replaced with a new simplified format using <code>+non_branch_link</code> and <code>+from_google_ad</code>.</p><p>If your app currently parses the old format, you will need to update your routing logic. Please contact our <a href="./submit-a-ticket.html">support team</a> to coordinate a transition timeline.</p></details><h3 id="meta-1" tabindex="-1">Meta <a class="header-anchor" href="#meta-1" aria-label="Permalink to &quot;Meta&quot;">​</a></h3><details><summary>Should I use SAN API DDL or Instant Experience for Meta?</summary><p>It depends on your campaign type and what data you need.</p><ul><li><strong>SAN API DDL</strong>:Use this if you run App Install campaigns and need campaign-level data (e.g. campaign name, ad set ID) for routing.</li><li><strong>Instant Experience DDL</strong>: Use this if you run web-based campaigns and need full Branch Link data (e.g. <code>$deeplink_path</code>, <code>$canonical_url</code>) for routing.</li></ul><p>Instant Experience may also work for App Install campaigns, but it introduces an additional interstitial step for users before the App Store page.</p></details><details><summary>I&#39;m already using Instant Experience for Meta DDL. Do I need to change anything?</summary><p>No. Instant Experience DDL and SAN API DDL are independent features. Enabling SAN API DDL does not affect your existing Instant Experience implementation.</p></details>`,41)])])}const g=a(s,[["render",i]]);export{h as __pageData,g as default};
